INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, level, topic_id, sort_order) VALUES
('w_travel_01', 'itinerary',    '/aɪˈtɪnərəri/', 'noun', '여행 일정',    'A planned route or journey, including details of places to visit.',        'Our {itinerary} includes three days in Kyoto and two in Tokyo.',           '우리 여행 일정에는 교토 3일과 도쿄 2일이 포함되어 있어요.',        'itinerary',    'B1', 'travel', 1),
('w_travel_02', 'departure',    '/dɪˈpɑːrtʃər/', 'noun', '출발',         'The action of leaving, especially to start a journey.',                    'The {departure} time is 6:45 in the morning.',                            '출발 시간은 아침 6시 45분이에요.',                                  'departure',    'B1', 'travel', 2),
('w_travel_03', 'arrival',      '/əˈraɪvəl/',    'noun', '도착',         'The action or process of arriving somewhere.',                             'Please go to the {arrival} hall to meet your guests.',                    '손님을 맞이하려면 도착 홀로 가세요.',                               'arrival',      'B1', 'travel', 3),
('w_travel_04', 'customs',      '/ˈkʌstəmz/',    'noun', '세관',         'The place at an airport where baggage is checked for illegal goods.',       'You must declare all goods at {customs}.',                                 '세관에서 모든 물품을 신고해야 해요.',                               'customs',      'B1', 'travel', 4),
('w_travel_05', 'luggage',      '/ˈlʌɡɪdʒ/',     'noun', '수하물, 짐',   'Bags and suitcases used when travelling.',                                 'You are allowed one piece of carry-on {luggage}.',                        '기내 수하물은 한 개만 허용돼요.',                                   'luggage',      'B1', 'travel', 5),
('w_travel_06', 'reservation',  '/ˌrezərˈveɪʃən/','noun','예약',         'An arrangement to have a seat, room, or table kept for you.',              'I have a {reservation} under the name Kim.',                              '김이라는 이름으로 예약했어요.',                                     'reservation',  'B1', 'travel', 6),
('w_travel_07', 'terminal',     '/ˈtɜːrmɪnəl/',  'noun', '터미널',       'A building at an airport where passengers arrive and depart.',              'The international flights depart from {terminal} two.',                    '국제선은 2터미널에서 출발해요.',                                    'terminal',     'B1', 'travel', 7),
('w_travel_08', 'transit',      '/ˈtrænsɪt/',    'noun', '환승, 경유',   'The process of passing through a place on the way to another destination.', 'We have a three-hour {transit} in Singapore.',                             '싱가포르에서 3시간 환승이 있어요.',                                 'transit',      'B1', 'travel', 8),
('w_travel_09', 'delay',        '/dɪˈleɪ/',      'noun', '지연, 연착',   'A period of time by which something is late or postponed.',                'There is a two-hour {delay} due to bad weather.',                         '악천후로 인해 두 시간 지연이 있어요.',                              'delay',        'B1', 'travel', 9),
('w_travel_10', 'destination',  '/ˌdestɪˈneɪʃən/','noun','목적지',       'The place to which someone is traveling.',                                 'Paris is our final {destination} on this trip.',                          '파리가 이번 여행의 최종 목적지예요.',                               'destination',  'B1', 'travel', 10);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, level, topic_id, beats, sort_order) VALUES
('s_travel_01', 'Could you tell me how to get to the departure terminal?',                   '출발 터미널까지 어떻게 가는지 알려주실 수 있나요?',                   'how to get to',          '"Could you tell me how to..."는 길을 물어볼 때 정중하고 자연스러운 표현이에요.',            '공항 길찾기',  'B1', 'travel', '[{"label":"공항 입구","tint":"#1a3a5c","time":"00:01"},{"label":"터미널 안내판","tint":"#2d4a6e","time":"00:08"}]', 1),
('s_travel_02', 'I''d like to check in my luggage and get a window seat if possible.',        '수하물을 맡기고 가능하면 창가 자리로 주세요.',                        'if possible',            '"if possible"을 끝에 붙이면 부탁이 훨씬 부드러워져요.',                                    '공항 체크인',  'B1', 'travel', '[{"label":"체크인 카운터","tint":"#1e4a7a","time":"00:01"},{"label":"탑승권 받기","tint":"#2a5a8a","time":"00:15"}]', 2),
('s_travel_03', 'My flight has been delayed, so I need to change my hotel reservation.',     '비행기가 연착되어서 호텔 예약을 변경해야 해요.',                       'has been delayed',       '"has been delayed"는 수동태로 항공사 안내 방송에서 자주 쓰는 표현이에요.',                 '예약 변경',    'B1', 'travel', '[{"label":"전광판 확인","tint":"#2a3a5c","time":"00:01"},{"label":"호텔 전화","tint":"#3a4a6c","time":"00:20"}]', 3),
('s_travel_04', 'Excuse me, is there a currency exchange counter near here?',                '실례합니다, 근처에 환전소가 있나요?',                                  'currency exchange',      '"Excuse me"로 시작하면 낯선 사람에게 자연스럽게 말을 걸 수 있어요.',                       '환전',         'B1', 'travel', '[{"label":"공항 로비","tint":"#1a4a3c","time":"00:01"},{"label":"환전소 발견","tint":"#2a5a4c","time":"00:12"}]', 4),
('s_travel_05', 'I''m here for sightseeing and plan to stay for about a week.',               '관광 목적으로 왔고 약 일주일 정도 머물 계획이에요.',                   'for sightseeing',        '입국심사에서 방문 목적을 묻는 질문에 쓸 수 있는 표현이에요.',                              '입국 심사',    'B1', 'travel', '[{"label":"입국심사대","tint":"#1a2a4c","time":"00:01"},{"label":"여권 제출","tint":"#2a3a5c","time":"00:10"}]', 5);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, level, topic_id, sort_order) VALUES
('w_cafe_01', 'recommend',    '/ˌrekəˈmend/',  'verb',      '추천하다',          'To suggest something as being good or suitable.',                           'Could you {recommend} a good local restaurant?',                          '좋은 현지 식당을 추천해 주실 수 있나요?',                           'recommend',    'B1', 'cafe', 1),
('w_cafe_02', 'appetizer',    '/ˈæpɪtaɪzər/',  'noun',      '에피타이저',        'A small dish eaten before the main course.',                                'Shall we order an {appetizer} to share?',                                 '나눠 먹을 에피타이저를 시킬까요?',                                  'appetizer',    'B1', 'cafe', 2),
('w_cafe_03', 'specialty',    '/ˈspeʃəlti/',   'noun',      '특선 요리',         'A dish or product for which a place is particularly well known.',           'The pasta is the chef''s {specialty}.',                                   '파스타가 셰프의 특선 요리예요.',                                    'specialty',    'B1', 'cafe', 3),
('w_cafe_04', 'portion',      '/ˈpɔːrʃən/',    'noun',      '1인분, 양',         'The amount of food served to one person.',                                  'The {portion} size here is really generous.',                             '여기 음식 양이 정말 넉넉해요.',                                     'portion',      'B1', 'cafe', 4),
('w_cafe_05', 'vegetarian',   '/ˌvedʒɪˈteəriən/','adjective','채식의',           'Not containing meat or fish.',                                              'Do you have any {vegetarian} options on the menu?',                       '메뉴에 채식 옵션이 있나요?',                                        'vegetarian',   'B1', 'cafe', 5),
('w_cafe_06', 'takeaway',     '/ˈteɪkəweɪ/',   'noun',      '포장 주문',         'Food bought at a restaurant to eat elsewhere.',                             'I''ll have my coffee as a {takeaway}, please.',                           '커피는 포장으로 주세요.',                                           'takeaway',     'A2', 'cafe', 6),
('w_cafe_07', 'complimentary','/ˌkɒmplɪˈmentri/','adjective','무료의, 서비스의', 'Given free of charge as a courtesy.',                                       'The bread and butter is {complimentary}.',                                '빵과 버터는 서비스예요.',                                           'complimentary','B2', 'cafe', 7),
('w_cafe_08', 'allergy',      '/ˈælədʒi/',     'noun',      '알레르기',          'A medical condition causing reactions to certain foods or substances.',     'I have a nut {allergy}, so please check the ingredients.',                '견과류 알레르기가 있어서 재료를 확인해 주세요.',                    'allergy',      'B1', 'cafe', 8),
('w_cafe_09', 'refill',       '/ˈriːfɪl/',     'noun',      '리필',              'A fresh supply of a drink after the first has been consumed.',              'Could I get a {refill} on my water, please?',                             '물 리필 해주실 수 있나요?',                                         'refill',       'A2', 'cafe', 9),
('w_cafe_10', 'split',        '/splɪt/',        'verb',      '나누다 (계산)',      'To divide the cost of something between two or more people.',               'Should we {split} the bill?',                                             '계산을 나눠서 낼까요?',                                             'split',        'A2', 'cafe', 10);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, level, topic_id, beats, sort_order) VALUES
('s_cafe_01', 'Could I see the menu, please? And do you have any specials today?',           '메뉴판 볼 수 있을까요? 오늘 특선 요리가 있나요?',                    'any specials',           '"specials"는 그날의 특별 메뉴를 뜻해요. 현지인처럼 들리는 표현이에요.',                    '레스토랑 입장','B1', 'cafe', '[{"label":"레스토랑 입구","tint":"#3a2a1a","time":"00:01"},{"label":"메뉴 확인","tint":"#4a3a2a","time":"00:08"}]', 1),
('s_cafe_02', 'I''d like to order the pasta, but could you make it without onions?',          '파스타를 주문하고 싶은데, 양파 없이 만들어 주실 수 있나요?',          'make it without',        '음식 재료를 빼달라고 할 때 "make it without ~" 패턴이 유용해요.',                          '주문',         'B1', 'cafe', '[{"label":"웨이터와 대화","tint":"#3a2820","time":"00:01"},{"label":"주문 메모","tint":"#4a3828","time":"00:12"}]', 2),
('s_cafe_03', 'Excuse me, I think there''s a mistake in the bill.',                            '저기요, 계산서에 실수가 있는 것 같아요.',                             'I think there''s a mistake', '부드럽게 항의할 때 "I think"를 붙이면 직접적이지 않고 예의 있게 들려요.',               '계산',         'B1', 'cafe', '[{"label":"계산서 확인","tint":"#2a2a1a","time":"00:01"},{"label":"직원 호출","tint":"#3a3a2a","time":"00:10"}]', 3),
('s_cafe_04', 'What do you recommend for someone who doesn''t eat meat?',                     '고기를 먹지 않는 사람에게는 무엇을 추천하시나요?',                    'recommend for someone who', '"recommend for someone who ~"는 조건에 맞는 추천을 구할 때 쓰는 표현이에요.',          '메뉴 추천',    'B1', 'cafe', '[{"label":"메뉴판 보기","tint":"#2a3a2a","time":"00:01"},{"label":"직원에게 질문","tint":"#3a4a3a","time":"00:08"}]', 4),
('s_cafe_05', 'I''ll have a flat white, and could I also get a slice of the cheesecake?',     '플랫화이트 주세요, 그리고 치즈케이크 한 조각도 주실 수 있나요?',      'could I also get',       '"could I also get ~?"는 추가 주문할 때 자연스럽게 쓸 수 있어요.',                          '카페 주문',    'A2', 'cafe', '[{"label":"카페 카운터","tint":"#3a2a1a","time":"00:01"},{"label":"커피 받기","tint":"#5a4a2a","time":"00:20"}]', 5);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, level, topic_id, sort_order) VALUES
('w_daily_01', 'routine',      '/ruːˈtiːn/',    'noun',    '일과, 루틴',    'A regular sequence of actions followed at a fixed time.',                  'My morning {routine} includes exercise and coffee.',                       '저의 아침 일과에는 운동과 커피가 포함돼요.',                        'routine',      'B1', 'daily', 1),
('w_daily_02', 'commute',      '/kəˈmjuːt/',    'verb',    '통근하다',      'To travel regularly between home and work.',                               'I {commute} to work by subway every day.',                                '저는 매일 지하철로 출근해요.',                                      'commute',      'B1', 'daily', 2),
('w_daily_03', 'neighborhood', '/ˈneɪbərhʊd/',  'noun',    '동네',          'The area around where someone lives.',                                     'There''s a great new café in my {neighborhood}.',                         '우리 동네에 새로운 카페가 생겼어요.',                               'neighborhood', 'B1', 'daily', 3),
('w_daily_04', 'catch up',     '/kætʃ ʌp/',     'phrase',  '근황을 나누다', 'To exchange news with someone you have not seen recently.',                'We should {catch up} over coffee sometime.',                              '언제 커피 마시면서 근황 얘기해요.',                                 'catch up',     'B1', 'daily', 4),
('w_daily_05', 'exhausted',    '/ɪɡˈzɔːstɪd/', 'adjective','완전히 지친',  'Completely tired.',                                                         'I was {exhausted} after the long meeting.',                                '긴 회의 후에 완전히 지쳤어요.',                                     'exhausted',    'B1', 'daily', 5),
('w_daily_06', 'forecast',     '/ˈfɔːrkæst/',   'noun',    '예보',          'A prediction about future events, especially weather.',                    'The weather {forecast} says it will rain tomorrow.',                       '일기 예보에서 내일 비가 온다고 해요.',                              'forecast',     'B1', 'daily', 6),
('w_daily_07', 'lately',       '/ˈleɪtli/',     'adverb',  '최근에',        'Recently, in the recent past.',                                            'Have you been watching any good shows {lately}?',                         '최근에 재미있는 드라마 보고 있어요?',                               'lately',       'B1', 'daily', 7),
('w_daily_08', 'manage',       '/ˈmænɪdʒ/',     'verb',    '해내다',        'To succeed in doing something difficult.',                                  'Did you {manage} to finish the project on time?',                         '프로젝트를 제시간에 끝냈어요?',                                     'manage',       'B1', 'daily', 8),
('w_daily_09', 'actually',     '/ˈæktʃuəli/',   'adverb',  '사실은',        'In fact, used to emphasize a surprising truth.',                           '{Actually}, I''ve never been to that restaurant.',                        '사실은 그 식당에 한 번도 가본 적 없어요.',                          'Actually',     'A2', 'daily', 9),
('w_daily_10', 'appreciate',   '/əˈpriːʃieɪt/', 'verb',    '감사히 여기다', 'To recognize the value of something and feel grateful for it.',            'I really {appreciate} your help with this.',                              '이 일에 도움을 주셔서 정말 감사해요.',                              'appreciate',   'B1', 'daily', 10);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, level, topic_id, beats, sort_order) VALUES
('s_daily_01', 'I''ve been pretty busy lately — how have you been keeping?',                  '요즘 꽤 바빴어요. 어떻게 지내셨어요?',                               'how have you been keeping', '"How have you been keeping?"은 "잘 지냈어요?"보다 더 자연스러운 원어민 표현이에요.',    '근황 묻기',    'B1', 'daily', '[{"label":"카페 만남","tint":"#2a3a4a","time":"00:01"},{"label":"대화 중","tint":"#3a4a5a","time":"00:10"}]', 1),
('s_daily_02', 'The weather has been so unpredictable this week, hasn''t it?',                 '이번 주 날씨가 너무 변덕스럽죠, 그렇지 않나요?',                     'hasn''t it',             '부가의문문("hasn''t it?")을 붙이면 상대방의 동의를 구하는 자연스러운 표현이에요.',        '날씨 이야기',  'B1', 'daily', '[{"label":"창밖 풍경","tint":"#1a2a3a","time":"00:01"},{"label":"우산 챙기기","tint":"#2a3a4a","time":"00:15"}]', 2),
('s_daily_03', 'I actually managed to finish the book you recommended last month.',           '지난달에 추천해 주신 책을 다 읽었어요.',                              'managed to finish',      '"managed to"는 어렵거나 오래 걸리는 일을 해냈을 때 쓰는 표현이에요.',                    '취미 대화',    'B1', 'daily', '[{"label":"독서 중","tint":"#2a2a3a","time":"00:01"},{"label":"책 완독","tint":"#3a3a4a","time":"00:20"}]', 3),
('s_daily_04', 'We should definitely catch up properly over dinner sometime.',                '언제 저녁 먹으면서 제대로 이야기해요.',                               'catch up properly',      '"catch up properly"는 바빠서 자주 못 만나는 사람에게 쓰는 자연스러운 표현이에요.',       '약속 잡기',    'B1', 'daily', '[{"label":"헤어지는 장면","tint":"#1a3a2a","time":"00:01"},{"label":"일정 확인","tint":"#2a4a3a","time":"00:08"}]', 4),
('s_daily_05', 'To be honest, I haven''t been sleeping well lately.',                          '솔직히 말하면, 요즘 잠을 잘 못 자고 있어요.',                         'To be honest',           '"To be honest"로 시작하면 솔직한 속마음을 나눌 때 자연스럽게 들려요.',                    '일상 고민',    'B1', 'daily', '[{"label":"밤 풍경","tint":"#0a0a2a","time":"00:01"},{"label":"침대에 누워","tint":"#1a1a3a","time":"00:20"}]', 5);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, level, topic_id, sort_order) VALUES
('w_work_01', 'deadline',     '/ˈdedlaɪn/',    'noun', '마감일',       'The latest time by which something should be completed.',                   'The {deadline} for submissions is this Friday.',                           '제출 마감일은 이번 금요일이에요.',                                  'deadline',     'B1', 'work', 1),
('w_work_02', 'colleague',    '/ˈkɒliːɡ/',     'noun', '동료',         'A person with whom one works.',                                             'My {colleague} will handle the project while I''m away.',                 '제가 없는 동안 동료가 프로젝트를 맡아줄 거예요.',                  'colleague',    'B1', 'work', 2),
('w_work_03', 'presentation', '/ˌprezənˈteɪʃən/','noun','발표',        'A talk or display prepared and given to an audience.',                      'I have a {presentation} to the board next Monday.',                       '다음 주 월요일에 이사회 발표가 있어요.',                            'presentation', 'B1', 'work', 3),
('w_work_04', 'agenda',       '/əˈdʒendə/',    'noun', '안건, 의제',   'A list of items to be discussed at a meeting.',                             'Can you send me the meeting {agenda} in advance?',                        '회의 안건을 미리 보내주실 수 있나요?',                              'agenda',       'B1', 'work', 4),
('w_work_05', 'feedback',     '/ˈfiːdbæk/',    'noun', '피드백',       'Information about the quality of something, used as a basis for improvement.','I''d appreciate your {feedback} on my report.',                          '제 보고서에 대한 피드백 부탁드려요.',                               'feedback',     'B1', 'work', 5),
('w_work_06', 'priority',     '/praɪˈɔːrɪti/', 'noun', '우선순위',     'Something regarded as more important than other things.',                   'Customer satisfaction is our top {priority}.',                            '고객 만족이 우리의 최우선 순위예요.',                               'priority',     'B1', 'work', 6),
('w_work_07', 'schedule',     '/ˈskedʒuːl/',   'noun', '일정',         'A plan of things to be done and the times to do them.',                     'Let me check my {schedule} for next week.',                               '다음 주 일정을 확인해 볼게요.',                                     'schedule',     'B1', 'work', 7),
('w_work_08', 'update',       '/ˈʌpdeɪt/',     'noun', '최신 정보',    'The latest information about something.',                                   'Could you give us a quick {update} on the situation?',                    '상황에 대해 간략하게 업데이트해 주실 수 있나요?',                   'update',       'B1', 'work', 8),
('w_work_09', 'negotiate',    '/nɪˈɡoʊʃieɪt/', 'verb', '협상하다',     'To discuss something formally in order to reach an agreement.',             'We need to {negotiate} better terms with the supplier.',                   '공급업체와 더 좋은 조건으로 협상해야 해요.',                        'negotiate',    'B2', 'work', 9),
('w_work_10', 'delegate',     '/ˈdelɪɡeɪt/',   'verb', '위임하다',     'To give a task or responsibility to someone else.',                         'A good manager knows when to {delegate} tasks.',                          '좋은 관리자는 언제 업무를 위임할지 알아요.',                        'delegate',     'B2', 'work', 10);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, level, topic_id, beats, sort_order) VALUES
('s_work_01', 'I wanted to follow up on the email I sent you last week.',                    '지난주에 보낸 이메일에 대해 후속으로 연락드리려고요.',                'follow up on',           '"follow up on"은 이전 연락에 대해 다시 확인할 때 쓰는 비즈니스 필수 표현이에요.',       '이메일 후속',  'B1', 'work', '[{"label":"이메일 화면","tint":"#1a2a3a","time":"00:01"},{"label":"답장 대기","tint":"#2a3a4a","time":"00:15"}]', 1),
('s_work_02', 'Would it be possible to move the meeting to Thursday afternoon?',             '회의를 목요일 오후로 옮기는 게 가능할까요?',                          'Would it be possible to','정중하게 부탁할 때 "Would it be possible to ~?"는 격식 상황에서 가장 안전한 표현이에요.', '일정 조율',    'B1', 'work', '[{"label":"캘린더 확인","tint":"#1a3a2a","time":"00:01"},{"label":"회의실","tint":"#2a4a3a","time":"00:12"}]', 2),
('s_work_03', 'I just wanted to make sure we''re on the same page about the deadline.',      '마감일에 대해 서로 같은 이해를 하고 있는지 확인하고 싶었어요.',       'on the same page',       '"on the same page"는 모두가 같은 내용을 이해하고 있는지 확인할 때 쓰는 표현이에요.',     '프로젝트 확인','B1', 'work', '[{"label":"팀 회의","tint":"#2a2a3a","time":"00:01"},{"label":"화이트보드","tint":"#3a3a4a","time":"00:10"}]', 3),
('s_work_04', 'Do you have a moment? I''d like to get your feedback on this proposal.',      '잠깐 시간 있으세요? 이 제안서에 대한 피드백을 받고 싶어요.',          'Do you have a moment',   '"Do you have a moment?"는 바쁜 상대방에게 가볍게 말을 걸 때 쓰는 표현이에요.',           '피드백 요청',  'B1', 'work', '[{"label":"사무실 복도","tint":"#2a2a2a","time":"00:01"},{"label":"문서 검토","tint":"#3a3a3a","time":"00:12"}]', 4),
('s_work_05', 'Let me know if there''s anything I can do to help with the project.',         '프로젝트에 도움이 필요하면 언제든지 알려주세요.',                     'Let me know if',         '"Let me know if ~"는 도움을 자연스럽게 제안할 때 쓰는 표현이에요.',                       '도움 제안',    'A2', 'work', '[{"label":"팀원과 대화","tint":"#1a2a1a","time":"00:01"},{"label":"협업 장면","tint":"#2a3a2a","time":"00:10"}]', 5);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, level, topic_id, sort_order) VALUES
('w_emo_01', 'overwhelmed',  '/ˌoʊvərˈwelmd/','adjective','압도된, 너무 힘든','Feeling completely overcome with too much of something.',               'I feel {overwhelmed} with all these tasks at once.',                       '이 많은 일을 한꺼번에 하려니 너무 힘들어요.',                       'overwhelmed',  'B1', 'emotions', 1),
('w_emo_02', 'anxious',      '/ˈæŋkʃəs/',     'adjective','불안한, 걱정되는','Experiencing worry, unease, or nervousness.',                           'She felt {anxious} before her job interview.',                             '그녀는 취업 면접 전에 불안함을 느꼈어요.',                          'anxious',      'B1', 'emotions', 2),
('w_emo_03', 'relieved',     '/rɪˈliːvd/',    'adjective','안도한',           'No longer feeling anxious because something has happened.',            'I was so {relieved} when I found my lost wallet.',                         '잃어버린 지갑을 찾았을 때 정말 안도했어요.',                        'relieved',     'B1', 'emotions', 3),
('w_emo_04', 'frustrated',   '/ˈfrʌstreɪtɪd/','adjective','답답한, 좌절한',   'Feeling annoyed or upset due to inability to change something.',        'I get {frustrated} when people don''t listen.',                            '사람들이 들어주지 않으면 답답해요.',                                'frustrated',   'B1', 'emotions', 4),
('w_emo_05', 'grateful',     '/ˈɡreɪtfəl/',   'adjective','감사한',           'Feeling or showing thanks.',                                           'I''m so {grateful} for all your help.',                                    '도움에 정말 감사해요.',                                             'grateful',     'B1', 'emotions', 5),
('w_emo_06', 'embarrassed',  '/ɪmˈbærəst/',   'adjective','당황한, 창피한',   'Feeling ashamed or self-conscious.',                                   'I was so {embarrassed} when I forgot her name.',                           '그녀의 이름을 잊어버려서 너무 창피했어요.',                         'embarrassed',  'B1', 'emotions', 6),
('w_emo_07', 'delighted',    '/dɪˈlaɪtɪd/',   'adjective','기쁜, 매우 좋은',  'Feeling or showing great pleasure.',                                   'We''re {delighted} to announce the winner.',                               '수상자를 발표하게 되어 기쁩니다.',                                  'delighted',    'B1', 'emotions', 7),
('w_emo_08', 'proud',        '/praʊd/',        'adjective','뿌듯한, 자랑스러운','Feeling deep pleasure from an achievement.',                          'She was {proud} of finishing the marathon.',                               '마라톤을 완주해서 뿌듯했어요.',                                     'proud',        'A2', 'emotions', 8),
('w_emo_09', 'nervous',      '/ˈnɜːrvəs/',    'adjective','긴장한',           'Easily agitated; anxious.',                                            'I always feel {nervous} before a big presentation.',                       '큰 발표 전에는 항상 긴장돼요.',                                     'nervous',      'A2', 'emotions', 9),
('w_emo_10', 'upset',        '/ʌpˈset/',       'adjective','속상한, 화난',     'Unhappy, disappointed, or worried.',                                   'He was quite {upset} after hearing the news.',                             '그는 소식을 듣고 꽤 속상해했어요.',                                 'upset',        'A2', 'emotions', 10);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, level, topic_id, beats, sort_order) VALUES
('s_emo_01', 'I''m a bit nervous about the presentation, but I think I''m ready.',            '발표가 좀 긴장되지만, 준비는 된 것 같아요.',                          'a bit nervous',          '"a bit"을 붙이면 감정을 부드럽게 표현해서 더 자연스럽게 들려요.',                         '긴장 표현',    'B1', 'emotions', '[{"label":"발표 준비","tint":"#2a1a3a","time":"00:01"},{"label":"심호흡","tint":"#3a2a4a","time":"00:15"}]', 1),
('s_emo_02', 'I can''t tell you how relieved I was when everything worked out.',               '모든 게 잘 됐을 때 얼마나 안도했는지 말로 표현하기 어려워요.',        'I can''t tell you how',  '"I can''t tell you how ~"는 감정의 크기를 강조할 때 쓰는 원어민 표현이에요.',            '안도 표현',    'B1', 'emotions', '[{"label":"결과 확인","tint":"#1a3a1a","time":"00:01"},{"label":"안도 표정","tint":"#2a4a2a","time":"00:12"}]', 2),
('s_emo_03', 'I''m really proud of what our team has achieved this quarter.',                  '이번 분기에 우리 팀이 이뤄낸 것들이 정말 뿌듯해요.',                 'proud of what',          '"proud of what ~"은 결과에 대한 뿌듯함을 표현하는 자연스러운 패턴이에요.',               '성취 표현',    'B1', 'emotions', '[{"label":"팀 성과 발표","tint":"#1a2a3a","time":"00:01"},{"label":"박수","tint":"#2a3a4a","time":"00:20"}]', 3),
('s_emo_04', 'It means a lot to me that you took the time to help.',                         '시간 내서 도와주셔서 정말 감사해요.',                                 'It means a lot to me',  '"It means a lot to me"는 "thank you"보다 훨씬 따뜻하고 진심 어린 감사 표현이에요.',     '감사 표현',    'B1', 'emotions', '[{"label":"도움받는 장면","tint":"#2a2a1a","time":"00:01"},{"label":"감사 인사","tint":"#3a3a2a","time":"00:10"}]', 4),
('s_emo_05', 'I was a little embarrassed, but I laughed it off in the end.',                 '좀 창피했지만 결국 웃어넘겼어요.',                                    'laughed it off',         '"laugh it off"는 창피하거나 불편한 상황을 웃음으로 넘기는 걸 표현해요.',                  '당황 표현',    'B1', 'emotions', '[{"label":"실수 장면","tint":"#3a2a1a","time":"00:01"},{"label":"웃음으로 넘기기","tint":"#4a3a2a","time":"00:15"}]', 5);
